sn_aia_tool.script:
(function(inputs) {
    var serial = inputs.serial_number;
    var gr = new GlideRecord('cmdb_ci_med_device');
    gr.addQuery('serial_number', serial);
    gr.orderByDesc('sys_created_on');
    gr.setLimit(1);
    gr.query();
    if (gr.next()) {
        var companyName = '';
        if (gr.getValue('company')) {
            var comp = new GlideRecord('core_company');
            if (comp.get(gr.getValue('company'))) {
                companyName = comp.getValue('name');
            }
        }
        var warrantyExp = gr.getValue('warranty_expiration') || '';
        var today = new GlideDate();
        var warrantyStatus = 'Unknown';
        if (warrantyExp) {
            var expDate = new GlideDate();
            expDate.setValue(warrantyExp);
            warrantyStatus = (expDate.compareTo(today) >= 0) ? 'ACTIVE' : 'EXPIRED';
        }
        var desc = gr.getValue('short_description') || '';
        var tier = 'Unknown';
        if (desc.indexOf('Gold') >= 0) tier = 'Gold';
        else if (desc.indexOf('Silver') >= 0) tier = 'Silver';
        else if (desc.indexOf('Bronze') >= 0) tier = 'Bronze';
        return JSON.stringify({
            status: 'success',
            device_name: gr.getValue('name'),
            device_sys_id: gr.getValue('sys_id'),
            serial_number: gr.getValue('serial_number'),
            warranty_expiration: warrantyExp,
            warranty_status: warrantyStatus,
            warranty_tier: tier,
            coverage_details: desc,
            customer_name: companyName,
            customer_sys_id: gr.getValue('company') || '',
            model_number: gr.getValue('model_number') || ''
        });
    } else {
        return JSON.stringify({ status: 'not_found', message: 'No device found with serial number: ' + serial });
    }
})(inputs);
